const input = $('2. Prepare Input').first().json;
const aiOutput = $json.output || '{}';

let vendors = [];
try {
  const parsed = JSON.parse(aiOutput.match(/```(?:json)?\s*([\s\S]*?)```/)?.[1] || aiOutput);
  vendors = parsed.vendors || [];
} catch (e) {
  vendors = [];
}

return {
  json: {
    vendors,
    totalFound: vendors.length,
    source: input.source,
    websiteUrl: input.websiteUrl,
    extractedAt: new Date().toISOString()
  }
};
